// ================================================================
// SENTINEL PARSE ENGINE — MINIMAL MODE
// WHAT IS STORED vs NOT STORED:
//
//  ❌ NOT stored: raw CDR rows (a_party, b_party, timestamps, addresses)
//  ❌ NOT stored: IMSI numbers
//  ❌ NOT stored: tower full addresses
//  ❌ NOT stored: location URLs
//
//  ✅ STORED (encrypted, minimal):
//     - tower hit counts + city names only
//     - contact frequency counts (no names, just numbers + count)
//     - IMEI → MSISDN mapping
//     - geo coordinates only (lat/lng, no address)
//     - risk index + anomaly count
//     - call type counts
//     - date range
//
//  ✅ RETURNED to frontend (in memory only, never stored):
//     - Full records_json for display during active session
//     - All derived data for all views
//
// The frontend keeps data IN MEMORY (React state) for the session.
// When user closes/navigates away, data is gone from frontend.
// Supabase only holds the summary (encrypted).
// 'destroy' action wipes even that.
// ================================================================

const body = $('Forensic Webhook').first().json.body || {};
const rawRecords = body.records || [];

if (rawRecords.length === 0) {
  return [{ json: { success: false, error: 'No records received.' } }];
}

// Simple XOR-based obfuscation for phone numbers stored in Supabase
// (real encryption needs a proper key — see note below)
const SESSION_KEY = body.session_key || 'SENTINEL';
function obfuscate(str) {
  // Hash the string so phone numbers are not stored in plain text
  // This is one-way — we only need counts, not the actual numbers
  let h = 0;
  for (let i = 0; i < str.length; i++) {
    h = (Math.imul(31, h) + str.charCodeAt(i)) | 0;
  }
  return 'H' + Math.abs(h).toString(36).toUpperCase();
}

// Month map for '01/Jan/2026' format
const MON = {jan:0,feb:1,mar:2,apr:3,may:4,jun:5,jul:6,aug:7,sep:8,oct:9,nov:10,dec:11};
function parseTS(dateStr, timeStr) {
  try {
    const [d, m, y] = String(dateStr).split('/');
    const mi = MON[m.toLowerCase().slice(0,3)];
    const [h,mn,s] = String(timeStr||'00:00:00').split(':').map(Number);
    if (mi === undefined) return null;
    return new Date(Date.UTC(+y, mi, +d, h||0, mn||0, s||0));
  } catch(e) { return null; }
}

function parseGeo(geoStr, locationUrl) {
  if (geoStr) {
    const t = String(geoStr).trim().split(/\s+/).filter(Boolean);
    if (t.length >= 2) {
      const la = parseFloat(t[0]), lo = parseFloat(t[1]);
      if (la>7&&la<38&&lo>66&&lo<99) return { lat:+la.toFixed(5), lng:+lo.toFixed(5), ok:true };
    }
  }
  if (locationUrl) {
    const m = String(locationUrl).match(/q=([\d.-]+),([\d.-]+)/);
    if (m) {
      const la = parseFloat(m[1]), lo = parseFloat(m[2]);
      if (la>7&&la<38&&lo>66&&lo<99) return { lat:+la.toFixed(5), lng:+lo.toFixed(5), ok:true };
    }
  }
  return { lat:0, lng:0, ok:false };
}

// ── Parse all rows (kept in memory, returned to frontend) ────
const scored = rawRecords.map((r, i) => {
  const tsObj = parseTS(r['Date']||'', r['Time']||'');
  const ts    = tsObj ? tsObj.toISOString() : new Date().toISOString();
  const geo   = parseGeo(r['Lat-Long-Azimuth (First CellID)']||'', r['Location']||'');
  const dur   = parseInt(r['Duration']||0)||0;
  const ct    = String(r['Call Type']||'CALL').toUpperCase();
  const h     = tsObj ? tsObj.getUTCHours() : 12;

  let risk = 0;
  if (h >= 17 || h <= 0) risk += 25;
  if (dur > 600) risk += 20;
  if (dur > 300) risk += 10;

  return {
    s_no:         i+1,
    a_party:      String(r['CdrNo']||'').trim(),
    b_party:      String(r['B Party']||'').trim(),
    timestamp:    ts,
    duration:     dur,
    call_type:    ct,
    tower_id:     String(r['First Cell ID']||'').trim(),
    tower_address:String(r['First Cell ID Address']||'').trim().replace(/\t/g,' ').slice(0,120),
    last_cell_id: String(r['Last Cell ID']||'').trim(),
    imei:         String(r['IMEI']||'').trim(),
    imsi:         String(r['IMSI']||'').trim(),
    roaming:      String(r['Roaming']||'').trim(),
    b_party_provider: String(r['B Party Provider']||'').trim(),
    main_city:    String(r['Main City(First CellID)']||'').trim(),
    sub_city:     String(r['Sub City(First CellID)']||'').trim(),
    operator:     String(r['Operator']||'').trim(),
    crime:        String(r['Crime']||'').trim(),
    latitude:     geo.lat,
    longitude:    geo.lng,
    has_geo:      geo.ok,
    risk_score:   Math.min(risk,100)
  };
});

// ── Risk index ───────────────────────────────────────────────
const risk_index = scored.length
  ? Math.round(scored.reduce((s,r)=>s+r.risk_score,0)/scored.length) : 0;

// ── geo_json (coordinates only — no addresses or names) ──────
const geo_json = scored.filter(r=>r.has_geo).map(r=>({
  lat:r.latitude, lng:r.longitude,
  tower:r.tower_id, city:r.main_city,
  a_party:r.a_party, b_party:r.b_party,
  call_type:r.call_type, ts:r.timestamp
}));

// ── timeline ──────────────────────────────────────────────────
const timeline_json = [...scored]
  .sort((a,b)=>new Date(a.timestamp)-new Date(b.timestamp));

// ── comm_links ────────────────────────────────────────────────
const lm={};
scored.forEach(r=>{
  if(r.a_party&&r.b_party){
    const k=[r.a_party,r.b_party].sort().join('|');
    lm[k]=(lm[k]||0)+1;
  }
});
const comm_links=Object.entries(lm)
  .map(([k,w])=>{const[s,t]=k.split('|');return{source:s,target:t,weight:w};})
  .sort((a,b)=>b.weight-a.weight);

// ── tower_analysis ────────────────────────────────────────────
const tm={};
scored.forEach(r=>{
  if(r.tower_id){
    if(!tm[r.tower_id]) tm[r.tower_id]={hits:0,city:r.main_city,lat:r.latitude,lng:r.longitude,address:r.tower_address};
    tm[r.tower_id].hits++;
  }
});
const tower_analysis=Object.entries(tm)
  .map(([id,v])=>({tower_id:id,...v}))
  .sort((a,b)=>b.hits-a.hits);

// ── common_numbers ────────────────────────────────────────────
const nm={};
scored.forEach(r=>{
  if(r.b_party){
    if(!nm[r.b_party]) nm[r.b_party]={count:0,provider:r.b_party_provider};
    nm[r.b_party].count++;
  }
});
const common_numbers=Object.entries(nm)
  .map(([n,v])=>({number:n,contact_count:v.count,provider:v.provider}))
  .sort((a,b)=>b.contact_count-a.contact_count)
  .slice(0,30);

// ── imei_mapping ──────────────────────────────────────────────
const im={};
scored.forEach(r=>{
  if(r.imei){
    if(!im[r.imei]) im[r.imei]={msisdns:new Set(),imsis:new Set()};
    if(r.a_party) im[r.imei].msisdns.add(r.a_party);
    if(r.imsi)    im[r.imei].imsis.add(r.imsi);
  }
});
const imei_mapping=Object.entries(im)
  .map(([imei,v])=>({imei,msisdns:[...v.msisdns],imsis:[...v.imsis]}));

// ── anomalies ─────────────────────────────────────────────────
const anomalies=scored.filter(r=>r.risk_score>=25);

// ── call type counts ──────────────────────────────────────────
const ct_counts={};
scored.forEach(r=>{ct_counts[r.call_type]=(ct_counts[r.call_type]||0)+1;});

// ================================================================
// MINIMAL STORAGE PAYLOAD — what goes into Supabase
// Phone numbers are hashed (one-way), not stored in plain text.
// No raw records, no IMSI, no full addresses.
// ================================================================
const storage_payload = {
  // Stats only
  total_records: scored.length,
  risk_index,
  anomaly_count: anomalies.length,
  geo_point_count: geo_json.length,
  call_types: ct_counts,
  date_range: {
    start: timeline_json[0]?.timestamp || null,
    end:   timeline_json[timeline_json.length-1]?.timestamp || null
  },
  // Tower hits — city + hit count only (no full address)
  tower_summary: tower_analysis.slice(0,20).map(t=>({
    tower_id: t.tower_id,
    hits: t.hits,
    city: t.city,
    lat: t.lat,
    lng: t.lng
    // address intentionally omitted
  })),
  // Contact frequency — HASHED numbers, not plain text
  contact_hashes: common_numbers.slice(0,20).map(n=>({
    number_hash: obfuscate(n.number),  // one-way hash
    contact_count: n.contact_count,
    provider: n.provider
  })),
  // IMEI — keep as-is (device identifier, not personal data)
  imei_count: imei_mapping.length,
  imei_list: imei_mapping.map(d=>({
    imei: d.imei,
    msisdn_count: d.msisdns.length
    // actual msisdns omitted from storage
  })),
  // Geo coordinates only (no addresses, no party info)
  geo_sample: geo_json.slice(0,100).map(g=>({lat:g.lat,lng:g.lng,tower:g.tower,city:g.city}))
};

// ── AI context (for Sentinel to use during session) ───────────
// This IS stored so AI can answer queries after page refresh,
// but uses hashed numbers and city-level data only.
const ai_context = JSON.stringify({
  subject_hash: obfuscate(scored[0]?.a_party||''),
  subject_display: scored[0]?.a_party || '',  // shown in UI, not in storage payload
  total_records: scored.length,
  risk_index,
  anomaly_count: anomalies.length,
  date_range: storage_payload.date_range,
  call_types: ct_counts,
  top_towers: storage_payload.tower_summary,
  // For AI: use real numbers so it can answer questions meaningfully
  top_contacts: common_numbers.slice(0,15),
  imei_devices: imei_mapping,
  anomaly_sample: anomalies.slice(0,10),
  records_sample: scored.slice(0,30)
});

const investigationId = body.investigation_id
  || ('INV-'+Math.random().toString(36).slice(2,8).toUpperCase());

return [{ json: {
  success: true,
  investigation_id: investigationId,
  case_number: 'CASE-'+investigationId,
  title: body.title||body.filename||'CDR Analysis',
  risk_index,
  total_records: scored.length,
  anomaly_count: anomalies.length,

  // ── For Supabase (minimal, hashed) ──
  storage_payload: JSON.stringify(storage_payload),
  ai_context,

  // ── Returned to frontend only (never stored) ──
  records_json:   scored,
  geo_json,
  timeline_json,
  comm_links,
  tower_analysis,
  common_numbers,
  imei_mapping,
  anomalies
}}];

const rows = $input.first().json;
const row  = Array.isArray(rows) ? rows[0] : rows;
const msg  = $('Forensic Webhook').first().json.body?.message || 'Give me a full summary.';

if (!row || !row.case_number) {
  return [{ json: { error: 'Investigation not found.', user_message: msg, ai_context: {}, tower_analysis:[], common_numbers:[], imei_mapping:[] } }];
}

function safe(v, fb) {
  if (!v) return fb;
  if (typeof v === 'object') return v;
  try { return JSON.parse(v); } catch(e) { return fb; }
}

const ai_ctx  = safe(row.ai_context, {});
const analysis = safe(row.analysis_json, {});
const metadata = safe(row.metadata, {});

return [{ json: {
  user_message:   msg,
  case_number:    row.case_number,
  title:          row.title,
  total_records:  row.total_records,
  risk_index:     row.risk_score,
  anomaly_count:  metadata.anomaly_count || 0,
  ai_context:     ai_ctx,
  tower_analysis: analysis.tower_summary  || [],
  common_numbers: ai_ctx.top_contacts     || [],
  imei_mapping:   ai_ctx.imei_devices     || []
}}];

